class TOTPAuthenticator:
    def __init__(self, issuer: str = "MyApp", digits: int = 6, period: int = 30, algorithm: str = "SHA1"):
        """
        Initialize TOTP Authenticator
        
        :param issuer: Name of the service/application
        :param digits: Number of digits in TOTP code (6 or 8)
        :param period: Time period in seconds (typically 30)
        :param algorithm: Hash algorithm (SHA1, SHA256, SHA512)
        """
        if digits not in [6, 8]:
            raise ValueError("Digits must be 6 or 8")
        
        if period <= 0:
            raise ValueError("Period must be positive")
        
        valid_algorithms = {"SHA1": hashlib.sha1, "SHA256": hashlib.sha256, "SHA512": hashlib.sha512}
        if algorithm.upper() not in valid_algorithms:
            raise ValueError(f"Algorithm must be one of {list(valid_algorithms.keys())}")
        
        self.issuer = issuer
        self.digits = digits
        self.period = period
        self.algorithm = algorithm.upper()
        self.hash_function = valid_algorithms[self.algorithm]
    
    def generate_secret(self, length: int = 32) -> str:
        """
        Generate a cryptographically secure random secret
        
        :param length: Length of the secret in bytes (default 32)
        :return: Base32 encoded secret
        """
        if length < 16:
            raise ValueError("Secret length should be at least 16 bytes for security")
        
        random_bytes = secrets.token_bytes(length)
        secret = base64.b32encode(random_bytes).decode('utf-8')
        return secret.rstrip('=')
    
    def _get_counter(self, timestamp: Optional[int] = None) -> int:
        """
        Calculate the counter value based on timestamp
        
        :param timestamp: Unix timestamp (uses current time if None)
        :return: Counter value
        """
        if timestamp is None:
            timestamp = int(time.time())
        
        return timestamp // self.period
    
    def _generate_hotp(self, secret: str, counter: int) -> str:
        """
        Generate HOTP (HMAC-based One-Time Password)
        
        :param secret: Base32 encoded secret
        :param counter: Counter value
        :return: HOTP code
        """
        # Decode the secret
        try:
            # Add padding if necessary
            missing_padding = len(secret) % 8
            if missing_padding:
                secret += '=' * (8 - missing_padding)
            
            key = base64.b32decode(secret, casefold=True)
        except Exception as e:
            raise ValueError(f"Invalid secret format: {e}")
        
        # Convert counter to bytes
        counter_bytes = struct.pack('>Q', counter)
        
        # Generate HMAC
        hmac_hash = hmac.new(key, counter_bytes, self.hash_function).digest()
        
        # Dynamic truncation
        offset = hmac_hash[-1] & 0x0F
        truncated_hash = struct.unpack('>I', hmac_hash[offset:offset + 4])[0]
        truncated_hash &= 0x7FFFFFFF
        
        # Generate OTP
        otp = truncated_hash % (10 ** self.digits)
        
        return str(otp).zfill(self.digits)
    
    def generate_totp(self, secret: str, timestamp: Optional[int] = None) -> str:
        """
        Generate TOTP code
        
        :param secret: Base32 encoded secret
        :param timestamp: Unix timestamp (uses current time if None)
        :return: TOTP code
        """
        counter = self._get_counter(timestamp)
        return self._generate_hotp(secret, counter)
    
    def verify_totp(self, secret: str, token: str, timestamp: Optional[int] = None, 
                    window: int = 1) -> bool:
        """
        Verify TOTP code with time window tolerance
        
        :param secret: Base32 encoded secret
        :param token: TOTP code to verify
        :param timestamp: Unix timestamp (uses current time if None)
        :param window: Number of time periods to check before and after (default 1)
        :return: True if valid, False otherwise
        """
        if not token or not isinstance(token, str):
            return False
        
        # Remove any whitespace
        token = token.strip()
        
        # Validate token format
        if not token.isdigit() or len(token) != self.digits:
            return False
        
        if timestamp is None:
            timestamp = int(time.time())
        
        # Check current time and window
        for i in range(-window, window + 1):
            check_timestamp = timestamp + (i * self.period)
            expected_token = self.generate_totp(secret, check_timestamp)
            
            # Use constant-time comparison to prevent timing attacks
            if self._constant_time_compare(token, expected_token):
                return True
        
        return False
    
    def _constant_time_compare(self, a: str, b: str) -> bool:
        """
        Constant-time string comparison to prevent timing attacks
        
        :param a: First string
        :param b: Second string
        :return: True if equal, False otherwise
        """
        if len(a) != len(b):
            return False
        
        result = 0
        for x, y in zip(a, b):
            result |= ord(x) ^ ord(y)
        
        return result == 0
    
    def get_provisioning_uri(self, secret: str, account_name: str) -> str:
        """
        Generate provisioning URI for QR code
        
        :param secret: Base32 encoded secret
        :param account_name: User's account name/email
        :return: otpauth:// URI
        """
        # URL encode parameters
        issuer_encoded = quote(self.issuer)
        account_encoded = quote(account_name)
        label = f"{issuer_encoded}:{account_encoded}"
        
        uri = f"otpauth://totp/{label}?secret={secret}&issuer={issuer_encoded}"
        uri += f"&digits={self.digits}&period={self.period}&algorithm={self.algorithm}"
        
        return uri
    
    def generate_qr_code(self, secret: str, account_name: str) -> BytesIO:
        """
        Generate QR code image for authenticator app
        
        :param secret: Base32 encoded secret
        :param account_name: User's account name/email
        :return: BytesIO object containing PNG image
        """
        uri = self.get_provisioning_uri(secret, account_name)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        img_buffer = BytesIO()
        img.save(img_buffer, format='PNG')
        img_buffer.seek(0)
        
        return img_buffer
    
    def get_remaining_time(self, timestamp: Optional[int] = None) -> int:
        """
        Get remaining seconds until next TOTP code
        
        :param timestamp: Unix timestamp (uses current time if None)
        :return: Remaining seconds
        """
        if timestamp is None:
            timestamp = int(time.time())
        
        return self.period - (timestamp % self.period)


class UserTOTPManager:
    """Manager class for handling user TOTP secrets"""
    
    def __init__(self, issuer: str = "MyApp"):
        self.authenticator = TOTPAuthenticator(issuer=issuer)
        self.user_secrets = {}
    
    def register_user(self, user_id: str, account_name: str) -> Tuple[str, BytesIO]:
        """
        Register a new user and generate their TOTP secret
        
        :param user_id: Unique user identifier
        :param account_name: User's account name/email
        :return: Tuple of (secret, qr_code_image)
        """
        if user_id in self.user_secrets:
            raise ValueError(f"User {user_id} already registered")
        
        secret = self.authenticator.generate_secret()
        self.user_secrets[user_id] = secret
        
        qr_code = self.authenticator.generate_qr_code(secret, account_name)
        
        return secret, qr_code
    
    def verify_user_token(self, user_id: str, token: str, window: int = 1) -> bool:
        """
        Verify a user's TOTP token
        
        :param user_id: Unique user identifier
        :param token: TOTP code to verify
        :param window: Time window tolerance
        :return: True if valid, False otherwise
        """
        if user_id not in self.user_secrets:
            return False
        
        secret = self.user_secrets[user_id]
        return self.authenticator.verify_totp(secret, token, window=window)
    
    def get_user_secret(self, user_id: str) -> Optional[str]:
        """
        Get user's secret (use with caution, only for backup purposes)
        
        :param user_id: Unique user identifier
        :return: Base32 encoded secret or None
        """
        return self.user_secrets.get(user_id)
    
    def remove_user(self, user_id: str) -> bool:
        """
        Remove user's TOTP configuration
        
        :param user_id: Unique user identifier
        :return: True if removed, False if user not found
        """
        if user_id in self.user_secrets:
            del self.user_secrets[user_id]
            return True
        return False


